#include <iostream>

int main() {
    unsigned n{};
    if (!(std::cin >> n) || n > 100000u) return 1;
    unsigned long long sum{};
    for (unsigned i = 1; i <= n; ++i) sum += i;
    std::cout << sum << '\n';
}
